$cmsAdminTitle='Section Components';require_once __DIR__.'/../includes/cms-admin-header.php';$error='';$sectionId=(int)($_GET['section']??0);
if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){try{$action=(string)($_POST['action']??'save');$id=(int)($_POST['id']??0);$sectionId=(int)($_POST['section_id']??$sectionId);if($action==='delete'){cms_require_delete_role();$pdo->prepare('DELETE FROM section_components WHERE id=?')->execute([$id]);}elseif($action==='toggle'){$pdo->prepare('UPDATE section_components SET is_active=1-is_active WHERE id=?')->execute([$id]);}elseif(in_array($action,['up','down'],true)){$pdo->prepare('UPDATE section_components SET sort_order=GREATEST(1,sort_order+?) WHERE id=?')->execute([$action==='up'?-1:1,$id]);}else{$settings=trim((string)$_POST['settings_json']);if($settings!==''&&!is_array(json_decode($settings,true)))throw new RuntimeException('Settings must be valid JSON.');$data=[$sectionId,$_POST['component_type'],trim((string)$_POST['title']),trim((string)$_POST['subtitle']),trim((string)$_POST['body_text']),trim((string)$_POST['icon']),(int)$_POST['media_id']?:null,trim((string)$_POST['button_text']),trim((string)$_POST['button_link']),trim((string)$_POST['accent_color']),$settings,max(1,(int)$_POST['sort_order']),isset($_POST['is_active'])?1:0];if($id){$data[]=$id;$pdo->prepare('UPDATE section_components SET section_id=?,component_type=?,title=?,subtitle=?,body_text=?,icon=?,media_id=?,button_text=?,button_link=?,accent_color=?,settings_json=?,sort_order=?,is_active=? WHERE id=?')->execute($data);}else{$pdo->prepare('INSERT INTO section_components (section_id,component_type,title,subtitle,body_text,icon,media_id,button_text,button_link,accent_color,settings_json,sort_order,is_active) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute($data);}}header('Location: academy-components.php?section='.$sectionId.'&saved=1');exit;}catch(Throwable $e){$error=$e->getMessage();}}
$sections=$pdo->query('SELECT id,page_key,admin_label,section_type FROM site_sections ORDER BY page_key,sort_order')->fetchAll();if(!$sectionId&&$sections)$sectionId=(int)$sections[0]['id'];$edit=null;if(!empty($_GET['edit'])){$s=$pdo->prepare('SELECT * FROM section_components WHERE id=?');$s->execute([(int)$_GET['edit']]);$edit=$s->fetch();if($edit)$sectionId=(int)$edit['section_id'];}$show=$edit||isset($_GET['new']);$media=cms_media_options($pdo);$s=$pdo->prepare('SELECT c.*,m.file_path FROM section_components c LEFT JOIN media_library m ON m.id=c.media_id WHERE c.section_id=? ORDER BY c.sort_order,c.id');$s->execute([$sectionId]);$items=$s->fetchAll();$current=null;foreach($sections as $sec)if((int)$sec['id']===$sectionId)$current=$sec;
