<div class="glass-card table-responsive"><h2><?=e($current['admin_label']??'Components')?></h2><table class="table table-dark"><tr><th>Order</th><th>Component</th><th>Type</th><th>Visible</th><th></th></tr><?php foreach($items as $item):?><tr><td><form class="order-actions" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="section_id" value="<?=$sectionId?>"><input type="hidden" name="id" value="<?=(int)$item['id']?>"><button class="btn btn-sm btn-outline-light" name="action" value="up">↑</button><button class="btn btn-sm btn-outline-light" name="action" value="down">↓</button></form></td><td><strong><?=e($item['icon'].' '.$item['title'])?></strong><small class="d-block text-secondary"><?=e(mb_strimwidth((string)$item['body_text'],0,90,'…'))?></small></td><td><?=e($item['component_type'])?></td><td><?=$item['is_active']?'Yes':'No'?></td><td><a class="btn btn-sm btn-outline-light" href="?edit=<?=(int)$item['id']?>">Edit</a><form class="d-inline" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="section_id" value="<?=$sectionId?>"><input type="hidden" name="id" value="<?=(int)$item['id']?>"><button class="btn btn-sm btn-outline-warning" name="action" value="toggle">Toggle</button><?php if(cms_can_delete()):?><button class="btn btn-sm btn-danger" name="action" value="delete">Delete</button><?php endif?></form></td></tr><?php endforeach?></table></div>
